span.t-attf-class:
badge bg-{{
                                                                        'success' if program.apply_state == 'submit' else
                                                                        'info' if program.apply_state == 'in_progress' else
                                                                        'warning'
                                                                    }}

badge bg-{{
                                                                        'success' if program.offer_letter_state == 'accepted' else
                                                                        'info' if program.offer_letter_state == 'issued' else
                                                                        'danger'
                                                                    }}

badge bg-{{
                                                                        'success' if program.visa_state == 'approve' else
                                                                        'danger' if program.visa_state == 'reject' else
                                                                        'info'
                                                                    }}

template.script:
/* ── portalSelectOption ─────────────────────────────────────────
   Called by Yes/No option buttons (type yes or no).
   Shows comment box + submit row for the current form.
─────────────────────────────────────────────────────────────── */
function portalSelectOption(btn) {
    var pid     = btn.getAttribute('data-pid');
    var optId   = btn.getAttribute('data-optid');
    var require = btn.getAttribute('data-require') === '1';

    var hiddenOptId  = document.getElementById('hiddenOptionId' + pid);
    var commentBlock = document.getElementById('commentBlock'   + pid);
    var commentText  = document.getElementById('commentText'    + pid);
    var commentReq   = document.getElementById('commentRequired'+ pid);
    var submitBlock  = document.getElementById('submitBlock'    + pid);

    if (!hiddenOptId || !commentBlock || !commentText || !submitBlock) {
        console.error('[portalSelectOption] Element(s) missing for pid=' + pid);
        return;
    }

    // Set hidden option_id
    hiddenOptId.value = optId;

    // Highlight chosen button — use data-pid to scope, not closest('form')
    document.querySelectorAll('[data-optid][data-pid="' + pid + '"]').forEach(function(b) {
        b.classList.remove('active', 'fw-bold');
    });
    btn.classList.add('active', 'fw-bold');

    // Show comment box always; mark required if needed
    commentBlock.style.display = 'block';
    if (require) {
        commentText.setAttribute('required', 'required');
        if (commentReq) commentReq.style.display = 'inline';
    } else {
        commentText.removeAttribute('required');
        if (commentReq) commentReq.style.display = 'none';
    }
    commentText.focus();

    // Show submit row
    submitBlock.style.display = 'block';
}

/* ── portalCancelForm ───────────────────────────────────────── */
function portalCancelForm(btn) {
    var pid = btn.getAttribute('data-pid');

    var hiddenOptId  = document.getElementById('hiddenOptionId' + pid);
    var commentBlock = document.getElementById('commentBlock'   + pid);
    var commentText  = document.getElementById('commentText'    + pid);
    var commentReq   = document.getElementById('commentRequired'+ pid);
    var submitBlock  = document.getElementById('submitBlock'    + pid);

    if (hiddenOptId)  hiddenOptId.value = '';
    document.querySelectorAll('[data-optid][data-pid="' + pid + '"]').forEach(function(b) {
        b.classList.remove('active', 'fw-bold');
    });
    if (commentBlock) commentBlock.style.display = 'none';
    if (submitBlock)  submitBlock.style.display  = 'none';
    if (commentText)  { commentText.value = ''; commentText.removeAttribute('required'); commentText.classList.remove('is-invalid'); }
    if (commentReq)   commentReq.style.display = 'none';
}

/* ── portalShowChangeForm ────────────────────────────────────── */
function portalShowChangeForm(pid) {
    var block = document.getElementById('changeFormBlock' + pid);
    if (block) block.style.display = 'block';
}

/* ── portalToggleNeutral ─────────────────────────────────────
   Toggles the comment box for a neutral option button.
   Same button click shows and hides (toggle).
─────────────────────────────────────────────────────────────── */
function portalToggleNeutral(btn) {
    var pid    = btn.getAttribute('data-pid');
    var noptId = btn.getAttribute('data-noptid');
    var block  = document.getElementById('neutralComment' + pid + '_' + noptId);
    var text   = document.getElementById('neutralText'    + pid + '_' + noptId);

    if (!block) return;
    if (block.style.display === 'none' || block.style.display === '') {
        block.style.display = 'block';
        if (text) text.focus();
    } else {
        block.style.display = 'none';
        if (text) text.value = '';
    }
}

/* ── portalValidateForm ─────────────────────────────────────
   onsubmit validator for Yes/No forms.
─────────────────────────────────────────────────────────────── */
function portalValidateForm(pid) {
    var hiddenOptId = document.getElementById('hiddenOptionId' + pid);
    var commentText = document.getElementById('commentText'    + pid);

    if (!hiddenOptId || !hiddenOptId.value) {
        alert('Please select an option before submitting.');
        return false;
    }
    if (commentText && commentText.hasAttribute('required') && !commentText.value.trim()) {
        commentText.classList.add('is-invalid');
        commentText.focus();
        alert('Please provide a comment before submitting.');
        return false;
    }
    if (commentText) commentText.classList.remove('is-invalid');
    return true;
}

/* ── portalValidateNeutralForm ──────────────────────────────
   onsubmit validator for neutral option forms.
─────────────────────────────────────────────────────────────── */
function portalValidateNeutralForm(pid, noptId, requireComment) {
    if (!requireComment) return true;
    var text = document.getElementById('neutralText' + pid + '_' + noptId);
    if (!text || !text.value.trim()) {
        if (text) { text.classList.add('is-invalid'); text.focus(); }
        alert('Please provide a comment before submitting.');
        return false;
    }
    if (text) text.classList.remove('is-invalid');
    return true;
}
